VALUES
  ('locality-6f0ba476-moex-00095', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司113年12月20日因倉庫大火，所有存貨付之一炬。113年至火災發生日止，相關資 料如下：期初存貨$70,000、銷貨收入$780,000、銷貨退回$45,000、銷貨運費$20,000、進貨 $575,000（包含一批起運點交貨之在途商品$50,000）、進貨退出$20,000、進貨運費$9,500。 已知甲公司之銷貨毛利率為30%，請問依毛利率法估計之火災損失為何？', '["$70,000", "$119,500", "$64,500", "$104,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00096', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '下列項目符合「不動產、廠房及設備」之定義者有幾項？①農產品  ②農業產品  ③生產性', '["礦業權及礦產  ⑤自用不動產  ⑥為賺取租金或資本增值所持有之不動產", "二項", "三項", "四項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00097', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司為購買$250,000之運輸貨車而於X1年1月1日支付現金$40,000並開立$210,000，3 年期，票面利率8%之分期付款票據，每年年底付款$81,487，第一次付款日為X1年12月31 日。試計算甲公司X2年應認列相關之利息費用（四捨五入至整數位）：', '["$10,281", "$11,625", "$16,800", "$20,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00098', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司為了蓋辦公大樓於X1年1月1日花$1,500,000以現金購買一塊土地，該土地上有一 棟舊倉庫。拆除該舊倉庫花費$50,000，並將殘料出售獲得$5,000。其他相關支出包括開挖地 基$25,000，代為支付前地主積欠地價稅$5,000，支付工程受益費$14,000，建屋材料及人工 $1,750,000，新大樓完工後估計比委外建造節省$340,000，則房屋成本為：', '["$1,775,000", "$1,794,000", "$1,839,000", "$3,320,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00099', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司將一筆金額頗大的設備維修費誤記為設備成本，請問此錯誤對當期的財務報表有何影響？', '["費用高估", "淨利高估", "資產不受影響", "淨利不受影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00100', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日購入機器一部$85,000，估計耐用年限為5年，殘值$4,000。公司 明訂採用直線法計算折舊費用，然而公司的會計人員未依規定，採用倍數（雙倍）餘額遞減 法計算折舊費用，在X1年12月31日倍數（雙倍）餘額遞減法下，公司的淨利為$66,000。 試計算公司採用直線法下之淨利：', '["$48,200", "$49,800", "$82,200", "$83,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00101', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司於 109 年 1 月 1 日購買一台特殊設備，成本為$1,450,000。公司預估該設備殘值為 $50,000，使用年限為7年，公司採用直線法折舊。甲公司在111年1月1日，將該設備的總 使用年限修訂為6年，殘值修訂為$30,000。甲公司將該設備於112年5月1日以$800,000售 出，請問公司出售該設備損失或利得為何？', '["損失$9,000", "損失$90,000", "利得$9,000", "利得$90,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00102', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司自X1年開始營業，主要的營業活動是生產及銷售筆記型電腦，並對於出售的產品提 供二年的保固服務。該公司估計：出售的產品在銷售後第一年被送回維修之費用約為銷貨收 入的2%，在銷售後第二年被送回維修之費用約為銷貨收入的5%。前二年筆記型電腦的銷貨 金額及實際保固服務支出資料如下： 年度 銷貨收入 實際保固服務支出 X1 $3,000,000 $ 50,000 X2 $3,600,000 $150,000 請問X2年底的保固負債準備餘額為何？', '["$200,000", "$222,000", "$262,000", "$282,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00103', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '甲公司面對一項法律訴訟，該公司法律顧問評估有10%之機率會勝訴而不會有成本，90%之 機率會敗訴，可能的賠償金額在$1,000,000～$6,000,000之間，其機率分布如下： 金 額 機 率 $1,000,000 10% $3,000,000 75% $6,000,000 15% 則甲公司有關該訴訟之會計處理為何？', '["應認列負債準備$2,700,000", "應認列負債準備$3,000,000", "應認列負債準備$3,250,000", "應認列負債準備$1,000,000，並附註揭露或有負債$5,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00104', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-e0b1f2ed', 'sub-locality-6f0ba476-01', NULL, 'single_choice', '下列何項無形資產無須攤銷？', '["取得之客戶名單，並預期該名單資訊能產生至少1年之效益，但不會超過3年", "取得將於3年內到期之廣播執照，執照主管機關決定不再展期廣播執照，公司預期該執照 將持續產生淨現金流入，直到該執照到期", "取得將於3年內到期且可以極低成本申請展期之歐洲兩城市間國際航空線行使權，企業作 需求及現金流量之分析後，預期將於非確定期間內自樞紐機場出發於兩城市間持續提供勞 務及使用相關基礎建設", "取得一預期產生淨現金流入至少15年之專利權，第三方承諾企業於5年內按專利權取得 日公允價值之60%購買該專利權，且企業有意圖於5年內出售該專利權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "62f8e785a7b3", "answer_pdf_sha1": "8a05b6f8fd08", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL)
